function smallest(arr) {
  let small = arr[0];
  for (let i = 1; i < arr.length; i++) {
    if (arr[i] < small) {      // use < to find minimum
      small = arr[i];
    }
  }
  return small;                // return after the loop
}

const arr = [2, 4, 43, 1, 3, 5, 6, 8, 9];
console.log(smallest(arr));    // 1
